CREATE TABLE IF NOT EXISTS program_iterations (id SERIAL PRIMARY KEY, "start" TIMESTAMP NOT NULL, "end" TIMESTAMP NULL, pid BIGINT NOT NULL, environment VARCHAR(10) NOT NULL);
CREATE TABLE IF NOT EXISTS request_iterations (id SERIAL PRIMARY KEY, "program" INT NOT NULL, program_id INT NOT NULL, "start" TIMESTAMP NOT NULL, "end" TIMESTAMP NULL, waiting_time BIGINT NULL, requesting_time BIGINT NULL, total_requests INT NULL, requested_users INT NULL, requested_projects INT NULL, requested_devlogs INT NULL, requested_project_followers INT NULL, requested_user_followers INT NULL, requested_user_following INT NULL, total_found INT NULL, found_users INT NULL, found_projects INT NULL, found_devlogs INT NULL, found_project_followers INT NULL, found_user_followers INT NULL, found_user_following INT NULL, total_unique INT NULL, unique_users INT NULL, unique_projects INT NULL, unique_devlogs INT NULL, unique_project_followers INT NULL, unique_user_followers INT NULL, unique_user_following INT NULL, total_errors INT NULL, total_warnings INT NULL, CONSTRAINT fk_request_iterations_program__id FOREIGN KEY ("program") REFERENCES program_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);
CREATE TABLE IF NOT EXISTS users ("name" VARCHAR(50) PRIMARY KEY, avatar_url VARCHAR(255) NOT NULL, bio VARCHAR(1000) NULL, slack_id VARCHAR(15) NULL, devlog_count INT NULL, project_count INT NULL, ship_count INT NULL, votes_count INT NULL, achievements_count INT NULL, follower_count INT NULL, following_count INT NULL, first_seen TIMESTAMP NOT NULL, last_requested TIMESTAMP NULL, last_requested_iteration INT NULL, CONSTRAINT fk_users_last_requested_iteration__id FOREIGN KEY (last_requested_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);
CREATE TABLE IF NOT EXISTS projects (id INT PRIMARY KEY, "owner" VARCHAR(50) NOT NULL, title VARCHAR(120) NULL, description VARCHAR(1000) NULL, "followerCount" INT NULL, "devlogCount" INT NULL, "totalHours" INT NULL, first_seen TIMESTAMP NOT NULL, last_requested TIMESTAMP NULL, last_requested_iteration INT NULL, CONSTRAINT fk_projects_owner__name FOREIGN KEY ("owner") REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_projects_last_requested_iteration__id FOREIGN KEY (last_requested_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);
CREATE TABLE IF NOT EXISTS project_followers (project INT, follower VARCHAR(50), first_seen TIMESTAMP NOT NULL, last_seen TIMESTAMP NOT NULL, last_seen_iteration INT NOT NULL, CONSTRAINT pk_project_followers PRIMARY KEY (project, follower), CONSTRAINT fk_project_followers_project__id FOREIGN KEY (project) REFERENCES projects(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_project_followers_follower__name FOREIGN KEY (follower) REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_project_followers_last_seen_iteration__id FOREIGN KEY (last_seen_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);
CREATE TABLE IF NOT EXISTS posts (id INT PRIMARY KEY, internal_id INT NOT NULL, "content" VARCHAR(4000) NOT NULL, author VARCHAR(50) NOT NULL, project INT NOT NULL, attachments_count INT DEFAULT 0 NOT NULL, "comments" INT DEFAULT 0 NOT NULL, reposts INT DEFAULT 0 NOT NULL, likes INT DEFAULT 0 NOT NULL, "views" INT DEFAULT 0 NOT NULL, created_at TIMESTAMP NOT NULL, time_logged BIGINT NOT NULL, first_seen TIMESTAMP NOT NULL, last_seen TIMESTAMP NOT NULL, last_seen_iteration INT NOT NULL, last_requested TIMESTAMP NULL, last_requested_iteration INT NULL, CONSTRAINT fk_posts_author__name FOREIGN KEY (author) REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_posts_project__id FOREIGN KEY (project) REFERENCES projects(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_posts_last_seen_iteration__id FOREIGN KEY (last_seen_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_posts_last_requested_iteration__id FOREIGN KEY (last_requested_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);
CREATE TABLE IF NOT EXISTS "comments" (devlog INT, "number" INT, author VARCHAR(50) NOT NULL, "content" VARCHAR(5000) NOT NULL, created TIMESTAMP NOT NULL, first_seen TIMESTAMP NOT NULL, last_seen TIMESTAMP NOT NULL, last_seen_iteration INT NOT NULL, CONSTRAINT pk_comments PRIMARY KEY (devlog, "number"), CONSTRAINT fk_comments_devlog__id FOREIGN KEY (devlog) REFERENCES posts(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_comments_author__name FOREIGN KEY (author) REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_comments_last_seen_iteration__id FOREIGN KEY (last_seen_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);
CREATE TABLE IF NOT EXISTS user_followers ("user" VARCHAR(50), follower VARCHAR(50), first_seen TIMESTAMP NOT NULL, last_seen TIMESTAMP NOT NULL, last_seen_iteration INT NOT NULL, CONSTRAINT pk_user_followers PRIMARY KEY ("user", follower), CONSTRAINT fk_user_followers_user__name FOREIGN KEY ("user") REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_user_followers_follower__name FOREIGN KEY (follower) REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_user_followers_last_seen_iteration__id FOREIGN KEY (last_seen_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);
CREATE INDEX user_followers_user ON user_followers ("user");
CREATE INDEX user_followers_follower ON user_followers (follower);